import os
import time
import logging
from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch, TransportError, ConnectionError as ESConnectionError, TimeoutError as ESTimeoutError

LOG_LEVEL = os.getenv("LOG_LEVEL", "INFO").upper()
logging.basicConfig(level=LOG_LEVEL, format="%(asctime)s %(levelname)s %(message)s")
logger = logging.getLogger("search_api")

ES_URL = os.getenv("ES_URL", "http://localhost:9200")
ES_API_KEY = os.getenv("ES_API_KEY")
ES_USER = os.getenv("ES_USER")
ES_PASSWORD = os.getenv("ES_PASSWORD")
ES_INDEX = os.getenv("ES_INDEX", "products")
ES_REQUEST_TIMEOUT = float(os.getenv("ES_REQUEST_TIMEOUT", "0.8"))
ES_MAX_RETRIES = int(os.getenv("ES_MAX_RETRIES", "2"))
ES_RETRY_ON_TIMEOUT = os.getenv("ES_RETRY_ON_TIMEOUT", "true").lower() == "true"

DEFAULT_SIZE = int(os.getenv("SEARCH_DEFAULT_SIZE", "20"))
MAX_SIZE = int(os.getenv("SEARCH_MAX_SIZE", "50"))
MIN_Q_LEN = int(os.getenv("SEARCH_MIN_Q_LEN", "1"))

app = Flask(__name__)

def _make_es_client():
    kwargs = {
        "hosts": [ES_URL],
        "request_timeout": ES_REQUEST_TIMEOUT,
        "max_retries": ES_MAX_RETRIES,
        "retry_on_timeout": ES_RETRY_ON_TIMEOUT,
    }
    if ES_API_KEY:
        kwargs["api_key"] = ES_API_KEY
    elif ES_USER and ES_PASSWORD:
        kwargs["basic_auth"] = (ES_USER, ES_PASSWORD)
    return Elasticsearch(**kwargs)

es = _make_es_client()

def _clamp_int(value, default, min_v, max_v):
    try:
        v = int(value)
    except (TypeError, ValueError):
        return default
    if v < min_v:
        return min_v
    if v > max_v:
        return max_v
    return v

def _build_query(q):
    q = (q or "").strip()
    return {
        "track_total_hits": False,
        "timeout": "300ms",
        "query": {
            "bool": {
                "must": [
                    {
                        "multi_match": {
                            "query": q,
                            "type": "best_fields",
                            "fields": [
                                "name^5",
                                "name.ngram^3",
                                "brand^2",
                                "category^1.5",
                                "description",
                                "keywords^2",
                            ],
                            "operator": "and",
                            "fuzziness": "AUTO",
                            "prefix_length": 1,
                            "max_expansions": 50,
                        }
                    }
                ],
                "filter": [
                    {"term": {"is_active": True}}
                ],
            }
        },
        "_source": ["id", "sku", "name", "brand", "category", "price", "currency", "image_url", "url", "in_stock"],
    }

def _format_hits(resp):
    hits = resp.get("hits", {}).get("hits", [])
    out = []
    for h in hits:
        src = h.get("_source") or {}
        out.append({
            "id": src.get("id"),
            "sku": src.get("sku"),
            "name": src.get("name"),
            "brand": src.get("brand"),
            "category": src.get("category"),
            "price": src.get("price"),
            "currency": src.get("currency"),
            "image_url": src.get("image_url"),
            "url": src.get("url"),
            "in_stock": src.get("in_stock"),
            "score": h.get("_score"),
        })
    return out

@app.get("/api/search")
def search_products():
    start = time.perf_counter()

    q = request.args.get("q", "", type=str)
    if q is None:
        q = ""
    q = q.strip()

    if len(q) < MIN_Q_LEN:
        return jsonify({
            "query": q,
            "took_ms": int((time.perf_counter() - start) * 1000),
            "count": 0,
            "results": [],
        }), 200

    size = _clamp_int(request.args.get("size"), DEFAULT_SIZE, 1, MAX_SIZE)
    from_ = _clamp_int(request.args.get("from"), 0, 0, 10000)

    body = _build_query(q)
    body["size"] = size
    body["from"] = from_

    try:
        resp = es.search(index=ES_INDEX, body=body)
        results = _format_hits(resp)
        took_ms = int((time.perf_counter() - start) * 1000)
        return jsonify({
            "query": q,
            "took_ms": took_ms,
            "count": len(results),
            "results": results,
        }), 200
    except (ESConnectionError, ESTimeoutError) as e:
        logger.warning("ES unavailable/timeout: %s", str(e))
        took_ms = int((time.perf_counter() - start) * 1000)
        return jsonify({
            "query": q,
            "took_ms": took_ms,
            "error": "search_unavailable",
            "results": [],
        }), 503
    except TransportError as e:
        logger.exception("ES transport error: %s", str(e))
        took_ms = int((time.perf_counter() - start) * 1000)
        return jsonify({
            "query": q,
            "took_ms": took_ms,
            "error": "search_error",
            "results": [],
        }), 500
    except Exception as e:
        logger.exception("Unhandled error: %s", str(e))
        took_ms = int((time.perf_counter() - start) * 1000)
        return jsonify({
            "query": q,
            "took_ms": took_ms,
            "error": "internal_error",
            "results": [],
        }), 500

